import{_ as t,c as o,o as a,a1 as s}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse(`{"title":"Statistiques Token : Surveillance des coûts et analyse des données | Antigravity Manager","description":"Apprenez à utiliser la fonction de statistiques Token. Comprenez comment extraire les données token des réponses, analyser l'utilisation par modèle et par compte, identifier les modèles et comptes les plus coûteux, et résoudre les problèmes de statistiques manquantes.","frontmatter":{"title":"Statistiques Token : Surveillance des coûts et analyse des données | Antigravity Manager","sidebarTitle":"Identifier rapidement ce qui coûte le plus","subtitle":"Statistiques Token : Surveillance des coûts et analyse des données","description":"Apprenez à utiliser la fonction de statistiques Token. Comprenez comment extraire les données token des réponses, analyser l'utilisation par modèle et par compte, identifier les modèles et comptes les plus coûteux, et résoudre les problèmes de statistiques manquantes.","tags":["Statistiques Token","Coûts","Surveillance","SQLite","Statistiques d'utilisation"],"prerequisite":["start-proxy-and-first-client","advanced-model-router"],"order":7},"headers":[],"relativePath":"fr/lbjlaq/Antigravity-Manager/advanced/token-stats/index.md","filePath":"fr/lbjlaq/Antigravity-Manager/advanced/token-stats/index.md"}`),r={name:"fr/lbjlaq/Antigravity-Manager/advanced/token-stats/index.md"};function i(n,e,u,d,l,c){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="statistiques-token-perspectives-de-statistiques-de-couts-et-interpretation-des-graphiques" tabindex="-1">Statistiques Token : Perspectives de statistiques de coûts et interprétation des graphiques <a class="header-anchor" href="#statistiques-token-perspectives-de-statistiques-de-couts-et-interpretation-des-graphiques" aria-label="Permalink to &quot;Statistiques Token : Perspectives de statistiques de coûts et interprétation des graphiques&quot;">​</a></h1><p>Vous avez déjà connecté vos clients à Antigravity Tools, mais &quot;qui consomme les coûts, où les coûts sont-ils élevés, et si un modèle a soudainement augmenté&quot; est généralement difficile à juger par intuition. Ce cours ne fait qu&#39;une seule chose : clarifier les critères de données dans la page Token Stats et vous enseigner à utiliser les graphiques pour localiser rapidement les problèmes de coûts.</p><h2 id="ce-que-vous-pourrez-faire-apres-ce-cours" tabindex="-1">Ce que vous pourrez faire après ce cours <a class="header-anchor" href="#ce-que-vous-pourrez-faire-apres-ce-cours" aria-label="Permalink to &quot;Ce que vous pourrez faire après ce cours&quot;">​</a></h2><ul><li>Expliquer clairement d&#39;où proviennent les données de Token Stats (quand elles sont enregistrées, dans quel cas elles manquent)</li><li>Basculer entre les fenêtres d&#39;observation par heure/jour/semaine pour éviter les erreurs de jugement dues à &quot;ne regarder qu&#39;un seul jour&quot;</li><li>Dans les deux vues &quot;par modèle/par compte&quot;, utiliser les graphiques de tendance pour identifier les pics anormaux</li><li>Utiliser la liste Top pour verrouiller le modèle/le compte le plus coûteux, puis revenir aux journaux de requêtes pour remonter à la cause racine</li></ul><h2 id="votre-situation-actuelle" tabindex="-1">Votre situation actuelle <a class="header-anchor" href="#votre-situation-actuelle" aria-label="Permalink to &quot;Votre situation actuelle&quot;">​</a></h2><ul><li>Vous avez l&#39;impression que les appels deviennent plus coûteux, mais vous ne savez pas si le modèle a changé, le compte a changé, ou si le volume a soudainement augmenté un certain jour</li><li>Vous avez vu <code>X-Mapped-Model</code>, mais vous n&#39;êtes pas sûr de quel critère de modèle les statistiques sont basées</li><li>Dans Token Stats, il y a parfois 0 ou &quot;pas de données&quot;, vous ne savez pas si c&#39;est qu&#39;il n&#39;y a pas de trafic ou que les statistiques ne sont pas enregistrées</li></ul><h2 id="quand-utiliser-cette-methode" tabindex="-1">Quand utiliser cette méthode <a class="header-anchor" href="#quand-utiliser-cette-methode" aria-label="Permalink to &quot;Quand utiliser cette méthode&quot;">​</a></h2><ul><li>Vous voulez optimiser les coûts : quantifiez d&#39;abord &quot;ce qui coûte le plus&quot;</li><li>Vous êtes en train de dépanner une limitation soudaine/anomalie : utilisez les points de temps de pic pour comparer avec les journaux de requêtes</li><li>Après avoir apporté des modifications à la configuration du routage de modèles ou de la gouvernance des quotas, vous voulez vérifier si les coûts ont diminué comme prévu</li></ul><h2 id="qu-est-ce-que-token-stats" tabindex="-1">Qu&#39;est-ce que Token Stats ? <a class="header-anchor" href="#qu-est-ce-que-token-stats" aria-label="Permalink to &quot;Qu&#39;est-ce que Token Stats ?&quot;">​</a></h2><p><strong>Token Stats</strong> est la page de statistiques d&#39;utilisation locale d&#39;Antigravity Tools : après avoir transféré la requête, le proxy tente d&#39;extraire le nombre de tokens de <code>usage/usageMetadata</code> dans la réponse JSON ou les données en streaming, et écrit chaque requête par compte et modèle dans le SQLite local (<code>token_stats.db</code>), puis affiche le résumé par temps/modèle/compte dans l&#39;interface utilisateur.</p><div class="info custom-block"><p class="custom-block-title">Clarification d&#39;un point facile à confondre</p><p>Le critère &quot;modèle&quot; de Token Stats provient du champ <code>model</code> de votre requête (ou de l&#39;analyse de chemin <code>/v1beta/models/&lt;model&gt;</code> de Gemini), et n&#39;est pas égal au <code>X-Mapped-Model</code> après le routage.</p></div><h2 id="🎒-preparation-avant-de-commencer" tabindex="-1">🎒 Préparation avant de commencer <a class="header-anchor" href="#🎒-preparation-avant-de-commencer" aria-label="Permalink to &quot;🎒 Préparation avant de commencer&quot;">​</a></h2><ul><li>Vous avez déjà réussi un appel de proxy (ne vous arrêtez pas seulement à <code>/healthz</code> pour vérifier la disponibilité)</li><li>Votre réponse amont retournera des champs de consommation de token analysables (sinon les statistiques manqueront)</li></ul><div class="tip custom-block"><p class="custom-block-title">Recommandation de lecture complémentaire</p><p>Si vous utilisez le mappage de modèles pour router <code>model</code> vers un autre modèle physique, il est recommandé de lire d&#39;abord <strong><a href="/docs/opencodedocs/fr/lbjlaq/Antigravity-Manager/advanced/model-router/">Routage de modèles : mappage personnalisé, priorité des caractères génériques et stratégies prédéfinies</a></strong>, puis revenir pour mieux comprendre &quot;les critères de statistiques&quot;.</p></div><h2 id="idee-centrale" tabindex="-1">Idée centrale <a class="header-anchor" href="#idee-centrale" aria-label="Permalink to &quot;Idée centrale&quot;">​</a></h2><p>Le pipeline de données de Token Stats peut être divisé en trois segments :</p><ol><li>Le middleware du proxy tente d&#39;extraire la consommation de token de la réponse (compatible avec <code>usage</code>/<code>usageMetadata</code>, le streaming est également analysé)</li><li>Si à la fois <code>account_email + input_tokens + output_tokens</code> sont obtenus, écrire dans le SQLite local (<code>token_stats.db</code>)</li><li>L&#39;interface utilisateur extrait les données agrégées via Tauri <code>invoke(get_token_stats_*)</code> et affiche par heure/jour/semaine</li></ol><h2 id="suivez-moi" tabindex="-1">Suivez-moi <a class="header-anchor" href="#suivez-moi" aria-label="Permalink to &quot;Suivez-moi&quot;">​</a></h2><h3 id="etape-1-confirmez-d-abord-que-vous-avez-du-trafic" tabindex="-1">Étape 1 : Confirmez d&#39;abord que vous &quot;avez du trafic&quot; <a class="header-anchor" href="#etape-1-confirmez-d-abord-que-vous-avez-du-trafic" aria-label="Permalink to &quot;Étape 1 : Confirmez d&#39;abord que vous &quot;avez du trafic&quot;&quot;">​</a></h3><p><strong>Pourquoi</strong> Les statistiques Token Stats proviennent de requêtes réelles. Si vous démarrez seulement le proxy sans avoir jamais envoyé de requête de modèle, la page affichera &quot;pas de données&quot;.</p><p>Procédure : Réutilisez la méthode d&#39;appel que vous avez déjà vérifiée avec succès dans <strong><a href="/docs/opencodedocs/fr/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">Démarrer le reverse proxy local et intégrer le premier client</a></strong> et envoyez 1-2 requêtes.</p><p><strong>Ce que vous devriez voir</strong> : La page Token Stats passe de &quot;chargement/pas de données&quot; à afficher des graphiques ou des listes.</p><h3 id="etape-2-choisissez-la-bonne-fenetre-de-temps-heure-jour-semaine" tabindex="-1">Étape 2 : Choisissez la bonne fenêtre de temps (heure/jour/semaine) <a class="header-anchor" href="#etape-2-choisissez-la-bonne-fenetre-de-temps-heure-jour-semaine" aria-label="Permalink to &quot;Étape 2 : Choisissez la bonne fenêtre de temps (heure/jour/semaine)&quot;">​</a></h3><p><strong>Pourquoi</strong> Avec les mêmes données, les &quot;pics/tendances&quot; vus dans différentes fenêtres sont complètement différents. Les trois fenêtres de l&#39;interface utilisateur correspondent également à différentes plages de récupération de données :</p><ul><li>Heure : dernières 24 heures</li><li>Jour : derniers 7 jours</li><li>Semaine : dernières 4 semaines (la vue de tendance agrège sur les 30 derniers jours)</li></ul><p><strong>Ce que vous devriez voir</strong> : Après le basculement, la granularité de l&#39;axe horizontal du graphique de tendance change (l&#39;heure affiche jusqu&#39;à &quot;heure&quot;, le jour affiche jusqu&#39;à &quot;mois/jour&quot;, la semaine affiche jusqu&#39;à &quot;année-W numéros de semaine&quot;).</p><h3 id="etape-3-regardez-d-abord-l-apercu-en-haut-determinez-l-echelle-des-couts" tabindex="-1">Étape 3 : Regardez d&#39;abord l&#39;aperçu en haut, déterminez &quot;l&#39;échelle des coûts&quot; <a class="header-anchor" href="#etape-3-regardez-d-abord-l-apercu-en-haut-determinez-l-echelle-des-couts" aria-label="Permalink to &quot;Étape 3 : Regardez d&#39;abord l&#39;aperçu en haut, déterminez &quot;l&#39;échelle des coûts&quot;&quot;">​</a></h3><p><strong>Pourquoi</strong> Les cartes d&#39;aperçu peuvent d&#39;abord répondre à 3 questions : le volume total est-il important, le ratio entrée/sortie est-il anormal, et le nombre de comptes/modèles participants a-t-il soudainement augmenté.</p><p>Concentrez-vous sur ces éléments :</p><ul><li>Total des tokens (<code>total_tokens</code>)</li><li>Tokens d&#39;entrée/sortie (<code>total_input_tokens</code> / <code>total_output_tokens</code>)</li><li>Nombre de comptes actifs (<code>unique_accounts</code>)</li><li>Nombre de modèles utilisés (l&#39;interface utilisateur utilise directement la longueur de &quot;la liste de statistiques par modèle&quot;)</li></ul><p><strong>Ce que vous devriez voir</strong> : Si le &quot;nombre de comptes actifs&quot; augmente soudainement, cela signifie généralement que vous avez exécuté plus de comptes en peu de temps (par exemple, en basculant vers une stratégie de rotation).</p><h3 id="etape-4-utilisez-les-tendances-d-utilisation-par-modele-par-compte-pour-capturer-les-pics-anormaux" tabindex="-1">Étape 4 : Utilisez &quot;les tendances d&#39;utilisation par modèle/par compte&quot; pour capturer les pics anormaux <a class="header-anchor" href="#etape-4-utilisez-les-tendances-d-utilisation-par-modele-par-compte-pour-capturer-les-pics-anormaux" aria-label="Permalink to &quot;Étape 4 : Utilisez &quot;les tendances d&#39;utilisation par modèle/par compte&quot; pour capturer les pics anormaux&quot;">​</a></h3><p><strong>Pourquoi</strong> Les graphiques de tendance sont le meilleur moyen de capturer &quot;soudainement plus coûteux&quot;. Vous n&#39;avez pas besoin de connaître la cause d&#39;abord, encerclez d&#39;abord &quot;quel jour/quel heure a augmenté&quot;.</p><p>Procédure :</p><ol><li>Dans le coin supérieur droit du graphique de tendance, basculez &quot;par modèle / par compte&quot;</li><li>Survolez (Tooltip) pour voir les valeurs Top, concentrez-vous d&#39;abord sur &quot;celle qui a soudainement sauté en premier&quot;</li></ol><p><strong>Ce que vous devriez voir</strong> :</p><ul><li>Par modèle : un modèle augmente soudainement dans une certaine période</li><li>Par compte : un compte augmente soudainement dans une certaine période</li></ul><h3 id="etape-5-utilisez-la-liste-top-pour-verrouiller-la-cible-la-plus-couteuse" tabindex="-1">Étape 5 : Utilisez la liste Top pour verrouiller &quot;la cible la plus coûteuse&quot; <a class="header-anchor" href="#etape-5-utilisez-la-liste-top-pour-verrouiller-la-cible-la-plus-couteuse" aria-label="Permalink to &quot;Étape 5 : Utilisez la liste Top pour verrouiller &quot;la cible la plus coûteuse&quot;&quot;">​</a></h3><p><strong>Pourquoi</strong> Le graphique de tendance vous dit &quot;quand c&#39;est anormal&quot;, la liste Top vous dit &quot;qui est le plus coûteux&quot;. En croisant ces deux, vous pouvez rapidement localiser la portée du dépannage.</p><p>Procédure :</p><ul><li>Dans la vue &quot;par modèle&quot;, regardez <code>total_tokens / request_count / proportion</code> du tableau &quot;statistiques détaillées par modèle&quot;</li><li>Dans la vue &quot;par compte&quot;, regardez <code>total_tokens / request_count</code> du tableau &quot;statistiques détaillées par compte&quot;</li></ul><p><strong>Ce que vous devriez voir</strong> : Le modèle/compte le plus coûteux est classé en premier, et <code>request_count</code> peut vous aider à distinguer &quot;une fois particulièrement coûteux&quot; ou &quot;nombre de fois particulièrement élevé&quot;.</p><h3 id="etape-6-optionnel-trouvez-token-stats-db-faites-une-sauvegarde-verification" tabindex="-1">Étape 6 (optionnel) : Trouvez <code>token_stats.db</code>, faites une sauvegarde/vérification <a class="header-anchor" href="#etape-6-optionnel-trouvez-token-stats-db-faites-une-sauvegarde-verification" aria-label="Permalink to &quot;Étape 6 (optionnel) : Trouvez `token_stats.db`, faites une sauvegarde/vérification&quot;">​</a></h3><p><strong>Pourquoi</strong> Lorsque vous soupçonnez &quot;statistiques manquantes&quot; ou souhaitez faire une analyse hors ligne, il est plus fiable de prendre directement le fichier SQLite.</p><p>Procédure : Entrez la zone Advanced de Settings, cliquez sur &quot;Ouvrir le répertoire de données&quot;, vous trouverez <code>token_stats.db</code> dans le répertoire de données.</p><p><strong>Ce que vous devriez voir</strong> : <code>token_stats.db</code> est présent dans la liste des fichiers (le nom de fichier est codé en dur par le backend).</p><h2 id="points-de-controle-✅" tabindex="-1">Points de contrôle ✅ <a class="header-anchor" href="#points-de-controle-✅" aria-label="Permalink to &quot;Points de contrôle ✅&quot;">​</a></h2><ul><li>Vous pouvez expliquer clairement que les statistiques Token Stats sont &quot;extraites de usage/usageMetadata dans la réponse puis écrites dans le SQLite local&quot;, et non la facturation cloud</li><li>Dans les deux vues de tendance &quot;par modèle/par compte&quot;, vous pouvez indiquer une période de pic spécifique</li><li>Vous pouvez utiliser la liste Top pour donner une conclusion de dépannage exécutable : d&#39;abord vérifier quel modèle ou compte</li></ul><h2 id="mises-en-garde-sur-les-pieges-courants" tabindex="-1">Mises en garde sur les pièges courants <a class="header-anchor" href="#mises-en-garde-sur-les-pieges-courants" aria-label="Permalink to &quot;Mises en garde sur les pièges courants&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Phénomène</th><th>Cause courante</th><th>Ce que vous pouvez faire</th></tr></thead><tbody><tr><td>Token Stats affiche &quot;pas de données&quot;</td><td>Vous n&#39;avez vraiment pas généré de requêtes de modèle ; ou la réponse amont ne contient pas de champs token analysables</td><td>Réutilisez d&#39;abord un client vérifié pour envoyer des requêtes ; puis vérifiez si la réponse contient <code>usage/usageMetadata</code></td></tr><tr><td>Les statistiques par &quot;modèle&quot; semblent incorrectes</td><td>Le critère de statistique utilise le <code>model</code> de la requête, et non le <code>X-Mapped-Model</code></td><td>Considérez le routage de modèles comme &quot;modèle de requête -&gt; modèle mappé&quot; ; les statistiques regardent le &quot;modèle de requête&quot;</td></tr><tr><td>Dimension compte manquante</td><td>Écrit uniquement lorsque <code>X-Account-Email</code> est obtenu et la consommation de token est analysée</td><td>Confirmez que la requête a vraiment atteint le pool de comptes ; puis comparez avec les journaux de requêtes/les en-têtes de réponse</td></tr><tr><td>Les données statistiques sont trop grandes après avoir activé Proxy Monitor</td><td>Lorsque Proxy Monitor est activé, les tokens de chaque requête sont enregistrés deux fois</td><td>C&#39;est un détail d&#39;implémentation connu, cela n&#39;affecte pas l&#39;analyse de tendance relative ; si vous avez besoin de valeurs précises, vous pouvez temporairement désactiver le Monitor et retester</td></tr></tbody></table><h2 id="resume-de-ce-cours" tabindex="-1">Résumé de ce cours <a class="header-anchor" href="#resume-de-ce-cours" aria-label="Permalink to &quot;Résumé de ce cours&quot;">​</a></h2><ul><li>La valeur centrale de Token Stats est de &quot;quantifier les problèmes de coûts&quot;, d&#39;abord localiser, puis optimiser</li><li>Lors de l&#39;écriture des statistiques, le compte et la consommation de token sont obligatoires ; si le modèle manque, il sera enregistré comme <code>&quot;unknown&quot;</code> (cela n&#39;empêche pas l&#39;écriture)</li><li>Pour un contrôle des coûts plus précis, l&#39;étape suivante consiste généralement à revenir au routage de modèles ou à la gouvernance des quotas</li></ul><h2 id="apercu-du-prochain-cours" tabindex="-1">Aperçu du prochain cours <a class="header-anchor" href="#apercu-du-prochain-cours" aria-label="Permalink to &quot;Aperçu du prochain cours&quot;">​</a></h2><blockquote><p>Dans le prochain cours, nous résolvons les &quot;problèmes de stabilité invisibles&quot; dans les sessions longues : <strong><a href="/docs/opencodedocs/fr/lbjlaq/Antigravity-Manager/advanced/context-compression/">Stabilité des sessions longues : compression de contexte, cache de signatures et compression des résultats d&#39;outils</a></strong>.</p></blockquote><p>Vous apprendrez :</p><ul><li>Ce que fait la compression de contexte progressive à trois couches</li><li>Pourquoi le &quot;cache de signatures&quot; peut réduire les erreurs de signature 400</li><li>Ce qui est supprimé et ce qui est conservé dans la compression des résultats d&#39;outils</li></ul><hr><h2 id="annexe-reference-du-code-source" tabindex="-1">Annexe : Référence du code source <a class="header-anchor" href="#annexe-reference-du-code-source" aria-label="Permalink to &quot;Annexe : Référence du code source&quot;">​</a></h2><details><summary><strong>Cliquez pour développer et voir les emplacements du code source</strong></summary><blockquote><p>Dernière mise à jour : 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Fonction</th><th>Chemin du fichier</th><th>Numéros de ligne</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>UI Token Stats : basculement de fenêtre de temps/vue et récupération de données</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/TokenStats.tsx#L49-L166" target="_blank" rel="noreferrer"><code>src/pages/TokenStats.tsx</code></a></td><td>49-166</td></tr><tr><td>UI Token Stats : indication de données vides (&quot;pas de données&quot;)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/TokenStats.tsx#L458-L507" target="_blank" rel="noreferrer"><code>src/pages/TokenStats.tsx</code></a></td><td>458-507</td></tr><tr><td>Extraction de consommation de token : analyse du model depuis la requête, analyse de usage/usageMetadata depuis la réponse</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/middleware/monitor.rs#L32-L120" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/middleware/monitor.rs</code></a></td><td>32-120</td></tr><tr><td>Extraction de consommation de token : analyse du champ usage dans les réponses streaming et JSON</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/middleware/monitor.rs#L122-L336" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/middleware/monitor.rs</code></a></td><td>122-336</td></tr><tr><td>Point d&#39;écriture Token Stats : écriture dans SQLite après obtention du compte+token</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/monitor.rs#L79-L136" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/monitor.rs</code></a></td><td>79-136</td></tr><tr><td>Nom de fichier de base de données et structure de table : <code>token_stats.db</code> / <code>token_usage</code> / <code>token_stats_hourly</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L58-L126" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>58-126</td></tr><tr><td>Logique d&#39;écriture : <code>record_usage(account_email, model, input, output)</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L128-L159" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>128-159</td></tr><tr><td>Logique de requête : heure/jour/semaine, par compte/par modèle, tendance et aperçu</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L161-L555" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>161-555</td></tr><tr><td>Commande Tauri : <code>get_token_stats_*</code> exposé au frontend</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L791-L847" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>791-847</td></tr><tr><td>Initialisation de la base de données Token Stats au démarrage de l&#39;application</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/lib.rs#L50-L56" target="_blank" rel="noreferrer"><code>src-tauri/src/lib.rs</code></a></td><td>50-56</td></tr><tr><td>Page de paramètres : obtenir/ouvrir le répertoire de données (pour trouver <code>token_stats.db</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L76-L143" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>76-143</td></tr></tbody></table></details>',59)])])}const q=t(r,[["render",i]]);export{m as __pageData,q as default};
